snippet.async_client:
import asyncio

from seed import AsyncSeedApi, BondSingleLeg, Isin, Quantity, TakerParty, Trader

client = AsyncSeedApi(
    base_url="https://yourhost.com/path/to/api",
)


async def main() -> None:
    await client._.create(
        instrument=BondSingleLeg(
            identifier=Isin(
                isin="isin",
            ),
            quantity=Quantity(
                quantity=1.1,
                type="QUANTITY",
            ),
        ),
        taker=TakerParty(
            trader=Trader(
                uuid_=1,
            ),
        ),
    )


asyncio.run(main())
